configfiles.configfile:
{ "system": "$technology", "data_folder": "./", "create_bellavista_inputs": true,
"visualization_parameters": { "plot_image": true, #if $technology_conditional.plot_genes.plot_transcripts == "true": "plot_transcripts": true, #else "plot_transcripts": false, #end if #if $technology_conditional.plot_cell_segmentation.plot_cell_seg == "true": "plot_cell_seg": true, #else "plot_cell_seg": false, #end if #if $technology_conditional.plot_nuclear_segmentation.plot_nuclear_seg == "true": "plot_nuclear_seg": true, #else "plot_nuclear_seg": false, #end if "genes_visible_on_startup": false, #if $technology_conditional.plot_genes.plot_all_genes.all_genes == "Yes": "plot_allgenes": true, #else "plot_allgenes": false, #set $gene_list = ['"' + str(x.strip()) + '"' for x in str($technology_conditional.plot_genes.plot_all_genes.selected_genes).split(',')] #set $genes = ','.join($gene_list) "selected_genes": $genes, #end if "rotate_angle": $rotate_angle, "transcript_point_size": $transcript_point_size },
"input_files": { #set $last_index = len($technology_conditional.images) - 1 "images": [ #for $i in range(len($images)): "$images[$i].element_identifier.$images[$i].ext"#if $i != $last_index#,#end if #end for ], #if $technology_conditional.plot_cell_segmentation.plot_cell_seg == "true": "cell_segmentation": "${technology_conditional.plot_cell_segmentation.cell_segmentation.element_identifier}.${technology_conditional.plot_cell_segmentation.cell_segmentation.ext}", #end if #if $technology_conditional.plot_nuclear_segmentation.plot_nuclear_seg == "true": "nuclear_segmentation": "${technology_conditional.plot_nuclear_segmentation.nuclear_segmentation.element_identifier}.${technology_conditional.plot_nuclear_segmentation.nuclear_segmentation.ext}", #end if #if $technology_conditional.technology == "MERSCOPE": "um_to_px_transform": "micron_to_mosaic_pixel_transform.csv", #end if #if $technology_conditional.plot_genes.plot_transcripts == "true": "transcript_filename": "${technology_conditional.plot_genes.transcript_filename.element_identifier}.${technology_conditional.plot_genes.transcript_filename.ext}", #end if "z_plane": $technology_conditional.z_plane } }

citations.citation:
@Manual{github,
            title = {Open-source Visualization for Imaging-Based Spatial Transcriptomics},
